33	// this function receives 2 pointers (indicated by *) so it can set their values
34	void getColors(uint8_t value, uint8_t scheme, uint8_t *foreground, uint8_t *background)
35	// scheme must be a valid index into the table of 4 schemes
36	__CPROVER_requires(scheme < 4)
37	// both output pointers must point to writable bytes
38	__CPROVER_requires(__CPROVER_w_ok(foreground, sizeof(uint8_t)))
39	__CPROVER_requires(__CPROVER_w_ok(background, sizeof(uint8_t)))
40	__CPROVER_assigns(*foreground, *background)
41	// the exact bytes written: odd table index for foreground, even index for background
42	__CPROVER_ensures(*foreground == COLOR_SCHEMES_TABLE[scheme][(1 + value * 2) % 32])
43	__CPROVER_ensures(*background == COLOR_SCHEMES_TABLE[scheme][(0 + value * 2) % 32])
44	{
45		uint8_t original[] = {8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0};
46		uint8_t blackwhite[] = {232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0};
47		uint8_t bluered[] = {235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255};
48		uint8_t whiteblack[] = {255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255};
49		uint8_t *schemes[] = {original, blackwhite, bluered, whiteblack};
50		// modify the 'pointed to' variables (using a * on the left hand of the assignment)
51		*foreground = *(schemes[scheme] + (1 + value * 2) % sizeof(original));
52		*background = *(schemes[scheme] + (0 + value * 2) % sizeof(original));
53		// alternatively we could have returned a struct with two variables
54	}
55	
56	// Powers of ten as 64-bit constants, indexed 0..10. Used by the getDigitCount
57	// contract to pin down the returned digit count without overflow (10^10 does
58	// not fit in uint32_t).
59	#define DC_POW10(k) (((const uint64_t[]){ \
60		1ULL, 10ULL, 100ULL, 1000ULL, 10000ULL, 100000ULL, \
61		1000000ULL, 10000000ULL, 100000000ULL, 1000000000ULL, 10000000000ULL})[(k)])
62	
63	uint8_t getDigitCount(uint32_t number)
64	// the count of decimal digits of a uint32_t is between 1 (for 0..9) and 10
65	__CPROVER_ensures(__CPROVER_return_value >= 1 && __CPROVER_return_value <= 10)
66	// the result d is the unique value with number < 10^d ...
67	__CPROVER_ensures((uint64_t)number < DC_POW10((int)__CPROVER_return_value))
68	// ... and number >= 10^(d-1), except 0 (which has no nonzero leading digit)
69	__CPROVER_ensures(__CPROVER_return_value == 1 || (uint64_t)number >= DC_POW10((int)__CPROVER_return_value - 1))
70	{
71		uint8_t count = 0;
72		do
73		{
74			number /= 10;
75			count += 1;
76		} while (number);
77		return count;
78	}
79	
80	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
81	// clang-format off
82	// the board must be a readable 4x4 block of bytes
83	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
84	// scheme is forwarded to getColors, whose contract requires a valid index
85	__CPROVER_requires(scheme < 4)
86	// each cell is a power-of-two exponent; drawBoard computes 1 << board[x][y],
87	// which is undefined for shift counts >= 31, so bound every cell at 30
88	__CPROVER_requires(__CPROVER_forall {
89		int _k;
90		(0 <= _k && _k < SIZE * SIZE) ==> ((uint8_t *)board)[_k] <= 30
91	})
92	// drawBoard only reads the board and prints; it writes nothing observable
93	__CPROVER_assigns()
94	// clang-format on
95	{
96		uint8_t x, y, fg, bg;
97		printf("\033[H"); // move cursor to 0,0
98		printf("2048.c %17u pts\n\n", score);
99		for (y = 0; y < SIZE; y++)
100		{
101			for (x = 0; x < SIZE; x++)
102			{
103				// send the addresses of the foreground and background variables,
104				// so that they can be modified by the getColors function
105				getColors(board[x][y], scheme, &fg, &bg);
106				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
107				printf("       ");
108				printf("\033[m"); // reset all modes
109			}
110			printf("\n");
111			for (x = 0; x < SIZE; x++)
112			{
113				getColors(board[x][y], scheme, &fg, &bg);
114				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
115				if (board[x][y] != 0)
116				{
117					uint32_t number = 1 << board[x][y];
118					uint8_t t = 7 - getDigitCount(number);
119					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
120				}
121				else
122				{
123					printf("   ·   ");
124				}
125				printf("\033[m"); // reset all modes
126			}
127			printf("\n");
128			for (x = 0; x < SIZE; x++)
129			{
130				getColors(board[x][y], scheme, &fg, &bg);
131				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
132				printf("       ");
133				printf("\033[m"); // reset all modes
134			}
135			printf("\n");
136		}
137		printf("\n");
138		printf("        ←,↑,→,↓ or q        \n");
139		printf("\033[A"); // one line up
140	}
141	
142	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
143	// clang-format off
144	// the array must be a readable block of SIZE bytes
145	__CPROVER_requires(__CPROVER_is_fresh(array, sizeof(uint8_t[SIZE])))
146	// x is a valid index into the array (it is both read and used as a bound)
147	__CPROVER_requires(x < SIZE)
148	// when x >= 1 the scan runs down toward stop; stop must be reachable from x-1,
149	// otherwise the uint8_t loop counter t underflows below 0 and reads out of bounds
150	__CPROVER_requires(x == 0 || stop < x)
151	// findTarget only reads the array; it never writes anything observable
152	__CPROVER_assigns()
153	// when x is already the first slot the function short-circuits with 0
154	__CPROVER_ensures(x != 0 || __CPROVER_return_value == 0)
155	// the target never lies above the original position ...
156	__CPROVER_ensures(__CPROVER_return_value <= x)
157	// ... and (for x >= 1) never below the stop barrier
158	__CPROVER_ensures(x == 0 || __CPROVER_return_value >= stop)
159	// functional: if every cell in [stop, x) is empty, the target is the stop barrier.
160	// NB: quantifiers reading an is_fresh array must range over a CONSTANT bound
161	// ([0, SIZE)); a symbolic bound makes CBMC read a havoced copy. The real [stop, x)
162	// range is recovered by the inner guard.
163	__CPROVER_ensures(x == 0 ||
164		((__CPROVER_forall { int _z; (0 <= _z && _z < SIZE) ==>
165			((stop <= _z && _z < x) ==> ((const uint8_t *)array)[_z] == 0) })
166			==> __CPROVER_return_value == stop))
167	// functional: otherwise let p be the highest nonzero cell in [stop, x); the target
168	// is p itself when array[p] can merge with array[x], else the slot just above p
169	__CPROVER_ensures(x == 0 ||
170		__CPROVER_forall { int _p; (0 <= _p && _p < SIZE) ==>
171			((stop <= _p && _p < x && ((const uint8_t *)array)[_p] != 0 &&
172			 (__CPROVER_forall { int _q; (0 <= _q && _q < SIZE) ==>
173				((_p < _q && _q < x) ==> ((const uint8_t *)array)[_q] == 0) }))
174			==> __CPROVER_return_value ==
175			    (((const uint8_t *)array)[_p] == ((const uint8_t *)array)[x] ? (uint8_t)_p : (uint8_t)(_p + 1))) })
176	// clang-format on
177	{
178		uint8_t t;
179		// if the position is already on the first, don't evaluate
180		if (x == 0)
181		{
182			return x;
183		}
184		for (t = x - 1;; t--)
185		{
186			if (array[t] != 0)
187			{
188				if (array[t] != array[x])
189				{
190					// merge is not possible, take next position
191					return t + 1;
192				}
193				return t;
194			}
195			else
196			{
197				// we should not slide further, return this one
198				if (t == stop)
199				{
200					return t;
201				}
202			}
203		}
204		// we did not find a target
205		return x;
206	}
207	
208	// slideArray slides one row toward index 0, merging equal adjacent tiles per
209	// the game rules. Each cell holds a power-of-two exponent (0 == empty).
210	//
211	// The defining invariant of a slide is LEFT-PACKING: afterwards no nonzero cell
212	// follows a zero cell. This is the postcondition that carries the spec's weight
213	// -- it is purely over the post-state, so it stays cheap and is reachable within
214	// CBMC's shallow --depth budget, and it kills the structural mutants (loop
215	// bounds, the array[x] != 0 / t != x guards) because any of them leaves some
216	// gappy input un-compacted.
217	//
218	// NOTE on spec strength / depth budget (mirrors the notes on rotateBoard and
219	// addRandom): the natural functional postconditions -- "the tile weight
220	// sum(2^cell) is conserved" and "success is returned iff a cell changed" --
221	// both require __CPROVER_old history snapshots of all four cells. Empirically
222	// those snapshots consume enough depth that the postcondition block is no longer
223	// reached, at which point EVERY clause (packing included) passes vacuously and
224	// the kill score collapses from 6/10 to 1/10. So they are deliberately omitted:
225	// the cheap post-state-only properties below verify and kill far more. The
226	// surviving mutants (the array[t]==0 / array[t]==array[x] value choices and the
227	// stop = t + 1 barrier) only corrupt tile VALUES while still packing left, so
228	// only a weight/old-relational postcondition could catch them -- and that one
229	// cannot be reached here.
230	//
231	// Entry cells are bounded at exponent 29: a cell is incremented by at most one
232	// merge (once a merge target, `stop` bars it from re-merging, and the scan
233	// index x only increases so it never revisits an already merged/moved cell), so
234	// every output cell stays <= 30 and every `1 << array[...]` shift is well
235	// defined. The bound also discharges findTarget's preconditions at each call:
236	// x < SIZE holds from the loop, and x == 0 || stop < x is maintained because a
237	// merge sets stop = t + 1 with t < x, so stop <= x at that iteration and
238	// stop < x at every later one.
239	bool slideArray(uint8_t array[SIZE], uint32_t *score)
240	// clang-format off
241	// the array must be a writable block of SIZE bytes
242	__CPROVER_requires(__CPROVER_is_fresh(array, sizeof(uint8_t[SIZE])))
243	// the score is read (+=) and written; it must be a distinct, valid object
244	__CPROVER_requires(__CPROVER_is_fresh(score, sizeof(uint32_t)))
245	// each cell is a power-of-two exponent bounded at 29 so a single merge keeps it
246	// <= 30, keeping every `1 << array[...]` shift well defined
247	__CPROVER_requires(__CPROVER_forall {
248		int _k;
249		(0 <= _k && _k < SIZE) ==> ((const uint8_t *)array)[_k] <= 29
250	})
251	// slideArray permutes/merges the cells of the array in place and updates score
252	__CPROVER_assigns(__CPROVER_object_whole(array))
253	__CPROVER_assigns(*score)
254	// every output cell is still a valid exponent: a merge increments a cell at most once
255	__CPROVER_ensures(__CPROVER_forall {
256		int _k;
257		(0 <= _k && _k < SIZE) ==> ((const uint8_t *)array)[_k] <= 30
258	})
259	// after a slide all tiles are packed toward index 0: no nonzero cell follows a
260	// zero cell (the defining invariant of a 2048 slide)
261	__CPROVER_ensures(__CPROVER_forall {
262		int _j;
263		(0 <= _j && _j < SIZE - 1) ==>
264			(((const uint8_t *)array)[_j] == 0 ==> ((const uint8_t *)array)[_j + 1] == 0)
265	})
266	// clang-format on
267	{
268		bool success = false;
269		uint8_t x, t, stop = 0;
270	
271		for (x = 0; x < SIZE; x++)
272		{
273			if (array[x] != 0)
274			{
275				t = findTarget(array, x, stop);
276				// if target is not original position, then move or merge
277				if (t != x)
278				{
279					// if target is zero, this is a move
280					if (array[t] == 0)
281					{
282						array[t] = array[x];
283					}
284					else if (array[t] == array[x])
285					{
286						// merge (increase power of two)
287						array[t]++;
288						// increase score
289						*score += 1 << array[t];
290						// set stop to avoid double merge
291						stop = t + 1;
292					}
293					array[x] = 0;
294					success = true;
295				}
296			}
297		}
298		return success;
299	}
300	
301	// rotateBoard rotates the 4x4 board 90 degrees counter-clockwise in place:
302	// the cell that ends up at [i][j] is the cell that started at [j][SIZE-1-i], so
303	// each output cell is related to its pre-state source via __CPROVER_old.
304	// RB_EQ(i,j,oi,oj) asserts: new board[i][j] == old board[oi][oj].
305	//
306	// NOTE on spec strength / depth budget: avocado runs CBMC with `--depth 200`.
307	// rotateBoard's body is a tight nest of indexed array writes that nearly
308	// exhausts that budget on the full path, and every __CPROVER_old history
309	// snapshot consumes depth on top of it. A postcondition that snapshots all 16
310	// cells becomes unreachable and then vacuously passes for every mutant (the
311	// kill score collapses to 0). Empirically the kill score saturates at 12/29 for
312	// any reachable subset of the relational map, so we assert one representative
313	// cell from each corner-orbit of the two concentric rings: the outer ring's 4
314	// corners and the inner 2x2 block's 4 cells. This touches all four assignment
315	// statements of the rotation kernel while staying inside the depth budget. See
316	// the same depth caveat documented on addRandom.
317	#define RB_EQ(i, j, oi, oj) (board[i][j] == __CPROVER_old(board[oi][oj]))
318	// outer-ring corners, then inner 2x2 block
319	#define RB_ROTATED                                                  \
320		(RB_EQ(0, 0, 0, 3) && RB_EQ(0, 3, 3, 3) &&                      \
321		 RB_EQ(3, 3, 3, 0) && RB_EQ(3, 0, 0, 0) &&                      \
322		 RB_EQ(1, 1, 1, 2) && RB_EQ(1, 2, 2, 2) &&                      \
323		 RB_EQ(2, 2, 2, 1) && RB_EQ(2, 1, 1, 1))
324	
325	void rotateBoard(uint8_t board[SIZE][SIZE])
326	// clang-format off
327	// the board must be a writable 4x4 block of bytes
328	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
329	// rotateBoard only permutes the cells of the board in place
330	__CPROVER_assigns(__CPROVER_object_whole(board))
331	// every output cell equals its rotated pre-state source cell
332	__CPROVER_ensures(RB_ROTATED)
333	// clang-format on
334	{
335		uint8_t i, j, n = SIZE;
336		uint8_t tmp;
337		for (i = 0; i < n / 2; i++)
338		{
339			for (j = i; j < n - i - 1; j++)
340			{
341				tmp = board[i][j];
342				board[i][j] = board[j][n - i - 1];
343				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
344				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
345				board[n - j - 1][i] = tmp;
346			}
347		}
348	}
349	
350	// moveUp slides every row of the board toward index 0 by calling slideArray on
351	// each row in turn, OR-ing the per-row success flags. Each row is an independent
352	// SIZE-byte slide, so moveUp's contract is slideArray's row contract lifted to
353	// all SIZE rows of the flattened 16-byte board: every cell starts a valid
354	// exponent (<= 29), stays valid after at most one merge (<= 30), and each row
355	// ends packed (no nonzero cell follows a zero cell within that row, i.e. for any
356	// non-last-in-row index _k, board[_k]==0 implies board[_k+1]==0).
357	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
358	// clang-format off
359	// the board must be a writable 4x4 block of bytes
360	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
361	// the score is read (+=) and written; it must be a distinct, valid object
362	__CPROVER_requires(__CPROVER_is_fresh(score, sizeof(uint32_t)))
363	// each cell is a power-of-two exponent bounded at 29 so a single merge keeps it
364	// <= 30, keeping every `1 << ...` shift inside slideArray well defined
365	__CPROVER_requires(__CPROVER_forall {
366		int _k;
367		(0 <= _k && _k < SIZE * SIZE) ==> ((const uint8_t *)board)[_k] <= 29
368	})
369	// moveUp slides each row in place and accumulates merge scores into *score
370	__CPROVER_assigns(__CPROVER_object_whole(board))
371	__CPROVER_assigns(*score)
372	// every output cell is still a valid exponent: a merge increments a cell at most once
373	__CPROVER_ensures(__CPROVER_forall {
374		int _k;
375		(0 <= _k && _k < SIZE * SIZE) ==> ((const uint8_t *)board)[_k] <= 30
376	})
377	// after the slide each row is packed toward its index-0 end: no nonzero cell
378	// follows a zero cell within a row (_k not the last column: _k % SIZE != SIZE-1)
379	__CPROVER_ensures(__CPROVER_forall {
380		int _j;
381		(0 <= _j && _j < SIZE * SIZE && (_j % SIZE != SIZE - 1)) ==>
382			(((const uint8_t *)board)[_j] == 0 ==> ((const uint8_t *)board)[_j + 1] == 0)
383	})
384	// clang-format on
385	{
386		bool success = false;
387		uint8_t x;
388		for (x = 0; x < SIZE; x++)
389		{
390			success |= slideArray(board[x], score);
391		}
392		return success;
393	}
394	
395	// moveLeft rotates the board 90 degrees (one rotateBoard call), slides every row
396	// toward index 0 with moveUp, then rotates 270 degrees back (three more
397	// rotateBoard calls, completing a full turn). The net geometric effect is that
398	// each column is packed toward its low-index (top) end. Because the surrounding
399	// rotations are exact permutations, the value bound is preserved across the round
400	// trip: cells start as valid exponents (<= 29) and end <= 30 after at most one
401	// merge per cell inside moveUp.
402	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
403	// clang-format off
404	// the board must be a writable 4x4 block of bytes
405	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
406	// the score is read (+=) and written; it must be a distinct, valid object
407	__CPROVER_requires(__CPROVER_is_fresh(score, sizeof(uint32_t)))
408	// each cell is a power-of-two exponent bounded at 29 so a single merge keeps it
409	// <= 30, keeping every `1 << ...` shift inside slideArray well defined
410	__CPROVER_requires(__CPROVER_forall {
411		int _k;
412		(0 <= _k && _k < SIZE * SIZE) ==> ((const uint8_t *)board)[_k] <= 29
413	})
414	// moveLeft permutes and slides the board in place and accumulates into *score
415	__CPROVER_assigns(__CPROVER_object_whole(board))
416	__CPROVER_assigns(*score)
417	// every output cell is still a valid exponent: a merge increments a cell at most once
418	__CPROVER_ensures(__CPROVER_forall {
419		int _k;
420		(0 <= _k && _k < SIZE * SIZE) ==> ((const uint8_t *)board)[_k] <= 30
421	})
422	// after the slide each column is packed toward its low-index (top) end: no
423	// nonzero cell sits below a zero within a column. _k ranges over all but the
424	// last row (_k < SIZE*(SIZE-1)); _k + SIZE is the cell directly below it, so a
425	// zero cell forces the cell below it to be zero too.
426	__CPROVER_ensures(__CPROVER_forall {
427		int _j;
428		(0 <= _j && _j < SIZE * (SIZE - 1)) ==>
429			(((const uint8_t *)board)[_j] == 0 ==> ((const uint8_t *)board)[_j + SIZE] == 0)
430	})
431	// clang-format on
432	{
433		bool success;
434		rotateBoard(board);
435		success = moveUp(board, score);
436		rotateBoard(board);
437		rotateBoard(board);
438		rotateBoard(board);
439		return success;
440	}
441	
442	// moveDown rotates the board 180 degrees (two rotateBoard calls), slides every
443	// row toward index 0 with moveUp, then rotates 180 degrees back. The net effect
444	// is that each column is packed toward its high-index (bottom) end. Because the
445	// surrounding rotations are exact permutations, the value bound is preserved
446	// across the round trip: cells start as valid exponents (<= 29) and end <= 30
447	// after at most one merge per cell inside moveUp.
448	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
449	// clang-format off
450	// the board must be a writable 4x4 block of bytes
451	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
452	// the score is read (+=) and written; it must be a distinct, valid object
453	__CPROVER_requires(__CPROVER_is_fresh(score, sizeof(uint32_t)))
454	// each cell is a power-of-two exponent bounded at 29 so a single merge keeps it
455	// <= 30, keeping every `1 << ...` shift inside slideArray well defined
456	__CPROVER_requires(__CPROVER_forall {
457		int _k;
458		(0 <= _k && _k < SIZE * SIZE) ==> ((const uint8_t *)board)[_k] <= 29
459	})
460	// moveDown permutes and slides the board in place and accumulates into *score
461	__CPROVER_assigns(__CPROVER_object_whole(board))
462	__CPROVER_assigns(*score)
463	// every output cell is still a valid exponent: a merge increments a cell at most once
464	__CPROVER_ensures(__CPROVER_forall {
465		int _k;
466		(0 <= _k && _k < SIZE * SIZE) ==> ((const uint8_t *)board)[_k] <= 30
467	})
468	// after the slide each column is packed toward its high-index (bottom) end: no
469	// nonzero cell sits above a zero within a column. _k ranges over all but the
470	// last row (_k < SIZE*(SIZE-1)); _k + SIZE is the cell directly below it.
471	__CPROVER_ensures(__CPROVER_forall {
472		int _j;
473		(0 <= _j && _j < SIZE * (SIZE - 1)) ==>
474			(((const uint8_t *)board)[_j + SIZE] == 0 ==> ((const uint8_t *)board)[_j] == 0)
475	})
476	// clang-format on
477	{
478		bool success;
479		rotateBoard(board);
480		rotateBoard(board);
481		success = moveUp(board, score);
482		rotateBoard(board);
483		rotateBoard(board);
484		return success;
485	}
486	
487	// moveRight rotates the board 270 degrees (three rotateBoard calls), slides every
488	// row toward index 0 with moveUp, then rotates 90 degrees back, completing a full
489	// turn. The net effect is that each row is packed toward its high-index (right)
490	// end. Because the surrounding rotations are exact permutations, the value bound
491	// is preserved across the round trip: cells start as valid exponents (<= 29) and
492	// end <= 30 after at most one merge per cell inside moveUp.
493	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
494	// clang-format off
495	// the board must be a writable 4x4 block of bytes
496	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
497	// the score is read (+=) and written; it must be a distinct, valid object
498	__CPROVER_requires(__CPROVER_is_fresh(score, sizeof(uint32_t)))
499	// each cell is a power-of-two exponent bounded at 29 so a single merge keeps it
500	// <= 30, keeping every `1 << ...` shift inside slideArray well defined
501	__CPROVER_requires(__CPROVER_forall {
502		int _k;
503		(0 <= _k && _k < SIZE * SIZE) ==> ((const uint8_t *)board)[_k] <= 29
504	})
505	// moveRight permutes and slides the board in place and accumulates into *score
506	__CPROVER_assigns(__CPROVER_object_whole(board))
507	__CPROVER_assigns(*score)
508	// every output cell is still a valid exponent: a merge increments a cell at most once
509	__CPROVER_ensures(__CPROVER_forall {
510		int _k;
511		(0 <= _k && _k < SIZE * SIZE) ==> ((const uint8_t *)board)[_k] <= 30
512	})
513	// after the slide each row is packed toward its high-index (right) end: no nonzero
514	// cell sits to the left of a zero within a row. _k ranges over indices that are
515	// not the last column (_k % SIZE != SIZE - 1); _k + 1 is the cell to its right, so
516	// a zero cell to the right forces the cell to its left to be zero too.
517	__CPROVER_ensures(__CPROVER_forall {
518		int _j;
519		(0 <= _j && _j < SIZE * SIZE && (_j % SIZE != SIZE - 1)) ==>
520			(((const uint8_t *)board)[_j + 1] == 0 ==> ((const uint8_t *)board)[_j] == 0)
521	})
522	// clang-format on
523	{
524		bool success;
525		rotateBoard(board);
526		rotateBoard(board);
527		rotateBoard(board);
528		success = moveUp(board, score);
529		rotateBoard(board);
530		return success;
531	}
