533	// findPairDown returns true exactly when some vertically adjacent pair of cells
534	// is equal, i.e. board[x][y] == board[x][y+1] for some 0<=x<SIZE, 0<=y<SIZE-1.
535	// In the flattened 16-byte board such a pair is cells a and a+1 where a is any
536	// index that is not the last entry of its column (a % SIZE != SIZE-1). Phrasing
537	// the property as a single existential quantifier keeps it a one-constraint
538	// check, cheap enough to be reached under CBMC's shallow --depth bound (a fully
539	// expanded 12-way disjunction is not). It still pins down the exact comparison,
540	// the exact pair offset (+1), and the exact ranges, killing mutations of each.
541	#define FPD_ANY_PAIR                                                  \
542		__CPROVER_exists                                                  \
543		{                                                                \
544			int _a;                                                      \
545			(0 <= _a && _a < SIZE *SIZE && (_a % SIZE) != SIZE - 1) &&   \
546				((const uint8_t *)board)[_a] == ((const uint8_t *)board)[_a + 1] \
547		}
548	
549	bool findPairDown(uint8_t board[SIZE][SIZE])
550	// clang-format off
551	// the board must be a readable 4x4 block of bytes
552	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
553	// findPairDown only reads the board; it writes nothing
554	__CPROVER_assigns()
555	// the result is true exactly when some vertically adjacent pair is equal
556	__CPROVER_ensures(__CPROVER_return_value == (FPD_ANY_PAIR))
557	// clang-format on
558	{
559		bool success = false;
560		uint8_t x, y;
561		for (x = 0; x < SIZE; x++)
562		{
563			for (y = 0; y < SIZE - 1; y++)
564			{
565				if (board[x][y] == board[x][y + 1])
566					return true;
567			}
568		}
569		return success;
570	}
571	
572	// Indicator (0 or 1) for cell `i` of the flattened board being empty (== 0).
573	#define CE_EMPTY(i) (((const uint8_t *)board)[i] == 0)
574	// Exact number of empty cells in the flattened 4x4 board, as a literal sum so
575	// CBMC pins down the precise count (not just a bound), killing mutations of the
576	// comparison, the increment, and the loop bounds.
577	#define CE_TOTAL ( \
578		CE_EMPTY(0)  + CE_EMPTY(1)  + CE_EMPTY(2)  + CE_EMPTY(3)  + \
579		CE_EMPTY(4)  + CE_EMPTY(5)  + CE_EMPTY(6)  + CE_EMPTY(7)  + \
580		CE_EMPTY(8)  + CE_EMPTY(9)  + CE_EMPTY(10) + CE_EMPTY(11) + \
581		CE_EMPTY(12) + CE_EMPTY(13) + CE_EMPTY(14) + CE_EMPTY(15))
582	
583	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
584	// clang-format off
585	// the board must be a readable 4x4 block of bytes
586	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
587	// countEmpty only reads the board; it writes nothing
588	__CPROVER_assigns()
589	// the result is exactly the number of empty (zero-valued) cells
590	__CPROVER_ensures(__CPROVER_return_value == CE_TOTAL)
591	// clang-format on
592	{
593		uint8_t x, y;
594		uint8_t count = 0;
595		for (x = 0; x < SIZE; x++)
596		{
597			for (y = 0; y < SIZE; y++)
598			{
599				if (board[x][y] == 0)
600				{
601					count++;
602				}
603			}
604		}
605		return count;
606	}
607	
608	// Pre-state (entry) value of board cell [i][j]. gameEnded mutates the board via
609	// rotateBoard, so the postcondition must reference the original cells via old.
610	#define GE_OLD(i, j) __CPROVER_old(board[i][j])
611	// The board is full: no empty (zero) cell. gameEnded's first action is to return
612	// false when countEmpty > 0, so fullness is necessary for a "true" result.
613	#define GE_FULL                                                        \
614		(GE_OLD(0, 0) != 0 && GE_OLD(0, 1) != 0 && GE_OLD(0, 2) != 0 && GE_OLD(0, 3) != 0 && \
615		 GE_OLD(1, 0) != 0 && GE_OLD(1, 1) != 0 && GE_OLD(1, 2) != 0 && GE_OLD(1, 3) != 0 && \
616		 GE_OLD(2, 0) != 0 && GE_OLD(2, 1) != 0 && GE_OLD(2, 2) != 0 && GE_OLD(2, 3) != 0 && \
617		 GE_OLD(3, 0) != 0 && GE_OLD(3, 1) != 0 && GE_OLD(3, 2) != 0 && GE_OLD(3, 3) != 0)
618	// No vertically adjacent equal pair, i.e. findPairDown(board) is false on the
619	// (un-rotated) entry board: board[x][y] != board[x][y+1] for all x, 0<=y<SIZE-1.
620	#define GE_NO_VPAIR                                                    \
621		(GE_OLD(0, 0) != GE_OLD(0, 1) && GE_OLD(0, 1) != GE_OLD(0, 2) && GE_OLD(0, 2) != GE_OLD(0, 3) && \
622		 GE_OLD(1, 0) != GE_OLD(1, 1) && GE_OLD(1, 1) != GE_OLD(1, 2) && GE_OLD(1, 2) != GE_OLD(1, 3) && \
623		 GE_OLD(2, 0) != GE_OLD(2, 1) && GE_OLD(2, 1) != GE_OLD(2, 2) && GE_OLD(2, 2) != GE_OLD(2, 3) && \
624		 GE_OLD(3, 0) != GE_OLD(3, 1) && GE_OLD(3, 1) != GE_OLD(3, 2) && GE_OLD(3, 2) != GE_OLD(3, 3))
625	// No horizontally adjacent equal pair: board[x][y] != board[x+1][y]. After one
626	// rotateBoard, these become the vertical pairs that the second findPairDown
627	// inspects.
628	#define GE_NO_HPAIR                                                    \
629		(GE_OLD(0, 0) != GE_OLD(1, 0) && GE_OLD(1, 0) != GE_OLD(2, 0) && GE_OLD(2, 0) != GE_OLD(3, 0) && \
630		 GE_OLD(0, 1) != GE_OLD(1, 1) && GE_OLD(1, 1) != GE_OLD(2, 1) && GE_OLD(2, 1) != GE_OLD(3, 1) && \
631		 GE_OLD(0, 2) != GE_OLD(1, 2) && GE_OLD(1, 2) != GE_OLD(2, 2) && GE_OLD(2, 2) != GE_OLD(3, 2) && \
632		 GE_OLD(0, 3) != GE_OLD(1, 3) && GE_OLD(1, 3) != GE_OLD(2, 3) && GE_OLD(2, 3) != GE_OLD(3, 3))
633	
634	bool gameEnded(uint8_t board[SIZE][SIZE])
635	// clang-format off
636	// the board must be a writable 4x4 block of bytes (rotateBoard rotates in place)
637	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
638	// gameEnded permutes the board via its four rotateBoard calls; nothing else is
639	// observably written. The four rotations compose to the identity, but the
640	// callee contracts (deliberately weak per rotateBoard's documented depth note)
641	// do not let CBMC prove that, so the post-state board is treated as havoced.
642	__CPROVER_assigns(__CPROVER_object_whole(board))
643	// gameEnded returns true exactly when the board is full and has no orthogonally
644	// adjacent equal pair (no vertical pair, found directly by findPairDown; no
645	// horizontal pair, found by findPairDown after one rotateBoard). This is the
646	// true, complete specification of gameEnded.
647	//
648	// NOTE on what CBMC actually checks: avocado runs CBMC with a shallow --depth
649	// bound. The final `return ended` is reached only after four rotateBoard calls,
650	// a path that exceeds that bound, so it is never explored. The equivalence is
651	// therefore checked on the reachable early-return paths only: there return is
652	// false, and CBMC confirms (non-vacuously, via the exact countEmpty/findPairDown
653	// contracts) that the board is then indeed not-full or has a vertical pair, so
654	// the RHS is false too. The horizontal-pair conjunct documents intent but is
655	// exercised only on the unreached deep path. The five line-423 (countEmpty
656	// comparison) mutants survive for the same reason: their behavioural difference
657	// only surfaces at that depth-unreachable `return true`, so no postcondition can
658	// kill them without strengthening rotateBoard's (deliberately weak) contract.
659	__CPROVER_ensures(__CPROVER_return_value == (GE_FULL && GE_NO_VPAIR && GE_NO_HPAIR))
660	// clang-format on
661	{
662		bool ended = true;
663		if (countEmpty(board) > 0)
664			return false;
665		if (findPairDown(board))
666			return false;
667		rotateBoard(board);
668		if (findPairDown(board))
669			ended = false;
670		rotateBoard(board);
671		rotateBoard(board);
672		rotateBoard(board);
673		return ended;
674	}
