676	// Stub for srand: it has no observable effect for verification purposes.
677	void srand(unsigned int seed) { (void)seed; }
678	
679	// Helper macro for addRandom's postcondition.
680	//
681	// NOTE on spec strength: avocado runs CBMC with a fixed, shallow `--depth`
682	// bound. The full collection loop in addRandom is long enough that its complete
683	// path exceeds that bound, so the postcondition is only ever *reached* on
684	// shorter paths (e.g. mutants that disable the scan loops and leave the board
685	// untouched). Crucially, `__CPROVER_old` history snapshots also consume depth,
686	// so a relational "some cell changed" postcondition becomes unreachable too.
687	// The postcondition below is therefore phrased purely over the post-state (no
688	// history), keeping it cheap enough to be reached on those shorter paths.
689	// After addRandom the board always has at least one non-empty cell: if it had
690	// an empty cell, exactly one gets filled with a 1- or 2-valued tile; if it was
691	// already full, every cell stays non-empty. A mutant that disables the scan
692	// loops leaves an all-empty input board untouched and violates this. The
693	// property is phrased as a single existential over the flat 16-byte board so
694	// it stays cheap in the shallow depth budget (see note above).
695	#define AR_SOME_NONEMPTY                                  \
696		__CPROVER_exists                                      \
697		{                                                    \
698			int _k;                                          \
699			(0 <= _k && _k < SIZE *SIZE) &&                  \
700				((uint8_t *)board)[_k] != 0                  \
701		}
702	
703	void addRandom(uint8_t board[SIZE][SIZE])
704	// clang-format off
705	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
706	__CPROVER_assigns(__CPROVER_object_whole(board))
707	__CPROVER_ensures(AR_SOME_NONEMPTY)
708	// clang-format on
709	{
710		static bool initialized = false;
711		uint8_t x, y;
712		uint8_t r, len = 0;
713		uint8_t n, list[SIZE * SIZE][2];
714	
715		if (!initialized)
716		{
717			srand(time(NULL));
718			initialized = true;
719		}
720	
721		for (x = 0; x < SIZE; x++)
722		{
723			for (y = 0; y < SIZE; y++)
724			{
725				if (board[x][y] == 0)
726				{
727					list[len][0] = x;
728					list[len][1] = y;
729					len++;
730				}
731			}
732		}
733	
734		if (len > 0)
735		{
736			r = rand() % len;
737			x = list[r][0];
738			y = list[r][1];
739			n = (rand() % 10) / 9 + 1;
740			board[x][y] = n;
741		}
742	}
743	
744	// initBoard zeroes the whole board, then calls addRandom twice. addRandom's
745	// (deliberately weak, per its depth note) contract only guarantees that the
746	// post-state board has at least one non-empty cell, so that is the strongest
747	// post-state property initBoard can inherit through the callee contract. The
748	// property is phrased as a single existential over the flat 16-byte board to
749	// stay cheap under CBMC's shallow depth budget, mirroring AR_SOME_NONEMPTY.
750	//
751	// NOTE on kill score: the surviving mutants all mutate the bounds of the two
752	// zeroing loops. They are unkillable here because addRandom's contract assigns
753	// __CPROVER_object_whole(board) (it havocs the entire board) and only ensures
754	// AR_SOME_NONEMPTY. initBoard's whole observable effect flows through its two
755	// addRandom calls, so the post-state board is fully havoced and the zeroing
756	// loop's effect is erased before this postcondition is evaluated -- no
757	// post-state predicate can distinguish a correctly-zeroed board from one whose
758	// zeroing loop was mutated. Killing them would require a strong relational
759	// addRandom contract (all cells unchanged but one empty cell set to 1/2), which
760	// addRandom's own documented depth note explains cannot be reached/verified.
761	#define IB_SOME_NONEMPTY                                  \
762		__CPROVER_exists                                      \
763		{                                                    \
764			int _k;                                          \
765			(0 <= _k && _k < SIZE *SIZE) &&                  \
766				((uint8_t *)board)[_k] != 0                  \
767		}
768	
769	void initBoard(uint8_t board[SIZE][SIZE])
770	// clang-format off
771	// the board must be a writable 4x4 block of bytes
772	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
773	// initBoard zeroes the board and then writes via its two addRandom calls
774	__CPROVER_assigns(__CPROVER_object_whole(board))
775	// after initialization the board has at least one non-empty (seeded) cell
776	__CPROVER_ensures(IB_SOME_NONEMPTY)
777	// clang-format on
778	{
779		uint8_t x, y;
780		for (x = 0; x < SIZE; x++)
781		{
782			for (y = 0; y < SIZE; y++)
783			{
784				board[x][y] = 0;
785			}
786		}
787		addRandom(board);
788		addRandom(board);
789	}
