791	// Ghost call counters: each terminal-control stub bumps its counter so the
792	// setBufferedInput contract can observe exactly which library calls a given
793	// branch performs (the only externally-visible effect of the function).
794	int __tcgetattr_calls = 0;
795	int __tcsetattr_calls = 0;
796	
797	// CBMC has no model for these terminal-control library functions, so we supply
798	// non-deterministic stubs.  tcgetattr fills in the caller-provided termios
799	// struct with arbitrary settings; tcsetattr only inspects the struct it is
800	// given.  Each returns an arbitrary status code.
801	// These stubs carry no contract on purpose: the verification pipeline does not
802	// substitute contracts for them (they are external library calls), so their
803	// bodies are inlined into setBufferedInput.  Each merely records that it ran by
804	// bumping a call counter, which is what the setBufferedInput contract observes.
805	int tcgetattr(int fd, struct termios *termios_p)
806	{
807		__tcgetattr_calls++;
808		int result;
809		return result;
810	}
811	
812	int tcsetattr(int fd, int optional_actions, const struct termios *termios_p)
813	{
814		__tcsetattr_calls++;
815		int result;
816		return result;
817	}
818	
819	void setBufferedInput(bool enable)
820	// no terminal calls have been made yet (the counters start at zero)
821	__CPROVER_requires(__tcgetattr_calls == 0 && __tcsetattr_calls == 0)
822	// the inlined stub bodies bump these counters, so they are in the write frame
823	__CPROVER_assigns(__tcgetattr_calls, __tcsetattr_calls)
824	// The contract characterises the function by the terminal calls each branch
825	// makes.  Under verification the static `enabled` flag is false on entry, so:
826	//   * each branch runs at most once, hence neither call happens more than once,
827	__CPROVER_ensures(__tcgetattr_calls <= 1 && __tcsetattr_calls <= 1)
828	//   * tcgetattr only occurs in the disable branch, which also calls tcsetattr,
829	//     while the restore branch calls tcsetattr alone -- so a tcsetattr always
830	//     accompanies any tcgetattr,
831	__CPROVER_ensures(__tcsetattr_calls >= __tcgetattr_calls)
832	//   * the current settings are only queried (tcgetattr) when *disabling*
833	//     buffered input, never when enabling it,
834	__CPROVER_ensures(enable ==> __tcgetattr_calls == 0)
835	//   * the disable branch is guarded by `enabled` (false on entry), so a request
836	//     to disable buffered input is a no-op that makes no terminal calls at all.
837	__CPROVER_ensures(!enable ==> (__tcgetattr_calls == 0 && __tcsetattr_calls == 0))
838	{
839		static bool enabled = true;
840		static struct termios old;
841		struct termios new;
842	
843		if (enable && !enabled)
844		{
845			// restore the former settings
846			tcsetattr(STDIN_FILENO, TCSANOW, &old);
847			// set the new state
848			enabled = true;
849		}
850		else if (!enable && enabled)
851		{
852			// get the terminal settings for standard input
853			tcgetattr(STDIN_FILENO, &new);
854			// we want to keep the old setting to restore them at the end
855			old = new;
856			// disable canonical mode (buffered i/o) and local echo
857			new.c_lflag &= (~ICANON & ~ECHO);
858			// set the new settings immediately
859			tcsetattr(STDIN_FILENO, TCSANOW, &new);
860			// set the new state
861			enabled = false;
862		}
863	}
