865	bool testSucceed()
866	{
867		uint8_t array[SIZE];
868		// these are exponents with base 2 (1=2 2=4 3=8)
869		// data holds per line: 4x IN, 4x OUT, 1x POINTS
870		uint8_t data[] = {
871			0, 0, 0, 1, 1, 0, 0, 0, 0,
872			0, 0, 1, 1, 2, 0, 0, 0, 4,
873			0, 1, 0, 1, 2, 0, 0, 0, 4,
874			1, 0, 0, 1, 2, 0, 0, 0, 4,
875			1, 0, 1, 0, 2, 0, 0, 0, 4,
876			1, 1, 1, 0, 2, 1, 0, 0, 4,
877			1, 0, 1, 1, 2, 1, 0, 0, 4,
878			1, 1, 0, 1, 2, 1, 0, 0, 4,
879			1, 1, 1, 1, 2, 2, 0, 0, 8,
880			2, 2, 1, 1, 3, 2, 0, 0, 12,
881			1, 1, 2, 2, 2, 3, 0, 0, 12,
882			3, 0, 1, 1, 3, 2, 0, 0, 4,
883			2, 0, 1, 1, 2, 2, 0, 0, 4};
884		uint8_t *in, *out, *points;
885		uint8_t t, tests;
886		uint8_t i;
887		bool success = true;
888		uint32_t score;
889	
890		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
891		for (t = 0; t < tests; t++)
892		{
893			in = data + t * (2 * SIZE + 1);
894			out = in + SIZE;
895			points = in + 2 * SIZE;
896			for (i = 0; i < SIZE; i++)
897			{
898				array[i] = in[i];
899			}
900			score = 0;
901			slideArray(array, &score);
902			for (i = 0; i < SIZE; i++)
903			{
904				if (array[i] != out[i])
905				{
906					success = false;
907				}
908			}
909			if (score != *points)
910			{
911				success = false;
912			}
913			if (success == false)
914			{
915				for (i = 0; i < SIZE; i++)
916				{
917					printf("%u ", in[i]);
918				}
919				printf("=> ");
920				for (i = 0; i < SIZE; i++)
921				{
922					printf("%u ", array[i]);
923				}
924				printf("(%u points) expected ", score);
925				for (i = 0; i < SIZE; i++)
926				{
927					printf("%u ", in[i]);
928				}
929				printf("=> ");
930				for (i = 0; i < SIZE; i++)
931				{
932					printf("%u ", out[i]);
933				}
934				printf("(%u points)\n", *points);
935				break;
936			}
937		}
938		if (success)
939		{
940			printf("All %u tests executed successfully\n", tests);
941		}
942		return success;
943	}
