946	{
947		printf("         TERMINATED         \n");
948		setBufferedInput(true);
949		// make cursor visible, reset all modes
950		printf("\033[?25h\033[m");
951		exit(signum);
952	}
953	
954	int main(int argc, char *argv[])
955	{
956		uint8_t board[SIZE][SIZE];
957		uint8_t scheme = 0;
958		uint32_t score = 0;
959		int c;
960		bool success;
961	
962		// handle the command line options
963		if (argc > 1)
964		{
965			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
966			{
967				printf("Usage: 2048 [OPTION] | [MODE]\n");
968				printf("Play the game 2048 in the console\n\n");
969				printf("Options:\n");
970				printf("  -h,  --help       Show this help message.\n");
971				printf("  -v,  --version    Show version number.\n\n");
972				printf("Modes:\n");
973				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
974				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
975				return EXIT_SUCCESS;
976			}
977			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
978			{
979				printf("2048.c version %s\n", VERSION);
980				return EXIT_SUCCESS;
981			}
982			else if (strcmp(argv[1], "blackwhite") == 0)
983			{
984				scheme = 1;
985			}
986			else if (strcmp(argv[1], "bluered") == 0)
987			{
988				scheme = 2;
989			}
990			else if (strcmp(argv[1], "whiteblack") == 0)
991			{
992				scheme = 3;
993			}
994			else if (strcmp(argv[1], "test") == 0)
995			{
996				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
997			}
998			else
999			{
1000				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
1001				return EXIT_FAILURE;
1002			}
1003		}
1004	
1005		// make cursor invisible, erase entire screen
1006		printf("\033[?25l\033[2J");
1007	
1008		// register signal handler for when ctrl-c is pressed
1009		signal(SIGINT, signal_callback_handler);
1010	
1011		initBoard(board);
1012		setBufferedInput(false);
1013		drawBoard(board, scheme, score);
1014		while (true)
1015		{
1016			c = getchar();
1017			if (c == EOF)
1018			{
1019				puts("\nError! Cannot read keyboard input!");
1020				break;
1021			}
1022			switch (c)
1023			{
1024			case 52:  // '4' key
1025			case 97:  // 'a' key
1026			case 104: // 'h' key
1027			case 68:  // left arrow
1028				success = moveLeft(board, &score);
1029				break;
1030			case 54:  // '6' key
1031			case 100: // 'd' key
1032			case 108: // 'l' key
1033			case 67:  // right arrow
1034				success = moveRight(board, &score);
1035				break;
1036			case 56:  // '8' key
1037			case 119: // 'w' key
1038			case 107: // 'k' key
1039			case 65:  // up arrow
1040				success = moveUp(board, &score);
1041				break;
1042			case 50:  // '2' key
1043			case 115: // 's' key
1044			case 106: // 'j' key
1045			case 66:  // down arrow
1046				success = moveDown(board, &score);
1047				break;
1048			default:
1049				success = false;
1050			}
1051			if (success)
1052			{
1053				drawBoard(board, scheme, score);
1054				usleep(150 * 1000); // 150 ms
1055				addRandom(board);
1056				drawBoard(board, scheme, score);
1057				if (gameEnded(board))
1058				{
1059					printf("         GAME OVER          \n");
1060					break;
1061				}
1062			}
1063			if (c == 'q')
1064			{
1065				printf("        QUIT? (y/n)         \n");
1066				c = getchar();
1067				if (c == 'y')
1068				{
1069					break;
1070				}
1071				drawBoard(board, scheme, score);
1072			}
1073			if (c == 'r')
1074			{
1075				printf("       RESTART? (y/n)       \n");
1076				c = getchar();
1077				if (c == 'y')
1078				{
1079					initBoard(board);
1080					score = 0;
1081				}
1082				drawBoard(board, scheme, score);
1083			}
1084		}
1085		setBufferedInput(true);
1086	
1087		// make cursor visible, reset all modes
1088		printf("\033[?25h\033[m");
1089	
1090		return EXIT_SUCCESS;
1091	}
